import React, { useState } from 'react';

const Header = ({ activeSection, alerts = [], onClearAlerts }) => {
  const [showAlertModal, setShowAlertModal] = useState(false);
  const activeAlerts = alerts.filter(a => a.status === 'flagged' || a.status === 'blocked');

  const titles = {
    Dashboard: {
      title: 'Fraud Monitoring Dashboard',
      subtitle: 'Real-time overview of transaction activity and threat detection'
    },
    Simulation: {
      title: 'Transaction Simulation Engine',
      subtitle: 'Generate synthetic transactions to test anomaly detection rules and fraud scenarios'
    },
    Detection: {
      title: 'Anomaly Detection & Alerts',
      subtitle: 'Configure detection rules, review alerts, and manage fraud prevention strategies'
    },
    Analytics: {
      title: 'ML Analytics & API Gateway',
      subtitle: 'Machine learning model performance, training analytics, and API endpoint monitoring'
    },
    Transactions: {
      title: 'All Transactions',
      subtitle: 'Detailed log of all system transactions and simulation results'
    },
    Settings: {
      title: 'System Settings',
      subtitle: 'Configure global system parameters and user permissions'
    }
  };

  const current = titles[activeSection] || titles.Dashboard;

  return (
    <header style={{ 
      padding: '1.5rem 2rem', 
      borderBottom: '1px solid #1e293b',
      backgroundColor: '#0f172a',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      position: 'relative'
    }}>
      <div>
        <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'white', marginBottom: '0.25rem' }}>{current.title}</h2>
        <p style={{ color: '#94a3b8', fontSize: '0.875rem' }}>{current.subtitle}</p>
      </div>

      {/* Alert Icon with Badge */}
      <div 
        onClick={() => setShowAlertModal(!showAlertModal)}
        style={{ 
          position: 'relative', 
          cursor: 'pointer', 
          padding: '10px', 
          backgroundColor: '#1e293b', 
          borderRadius: '12px',
          border: activeAlerts.length > 0 ? '1px solid #ef4444' : '1px solid #334155',
          animation: activeAlerts.length > 0 ? 'pulse 2s infinite' : 'none'
        }}
      >
        <span style={{ fontSize: '1.5rem' }}>🔔</span>
        {activeAlerts.length > 0 && (
          <span style={{ 
            position: 'absolute', 
            top: '-5px', 
            right: '-5px', 
            backgroundColor: '#ef4444', 
            color: 'white', 
            borderRadius: '50%', 
            width: '20px', 
            height: '20px', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            fontSize: '0.75rem', 
            fontWeight: 'bold',
            boxShadow: '0 0 10px rgba(239, 68, 68, 0.5)'
          }}>
            {activeAlerts.length}
          </span>
        )}
      </div>

      {/* Alert Dropdown/Modal */}
      {showAlertModal && (
        <div style={{ 
          position: 'absolute', 
          top: '5.5rem', 
          right: '2rem', 
          width: '350px', 
          backgroundColor: '#1e293b', 
          borderRadius: '1rem', 
          border: '1px solid #334155', 
          zIndex: 1000, 
          boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.5)',
          maxHeight: '400px',
          overflowY: 'auto'
        }}>
          <div style={{ padding: '1rem', borderBottom: '1px solid #334155', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <h4 style={{ margin: 0 }}>Fraud Notifications</h4>
            <button 
              onClick={(e) => {
                e.stopPropagation();
                onClearAlerts();
              }} 
              style={{ background: 'none', border: 'none', color: '#3b82f6', cursor: 'pointer', fontSize: '0.8rem' }}
            >
              Clear All
            </button>
          </div>
          <div style={{ padding: '0.5rem' }}>
            {activeAlerts.length === 0 ? (
              <p style={{ padding: '1rem', textAlign: 'center', color: '#64748b' }}>No recent fraud alerts</p>
            ) : (
              activeAlerts.map((alert, i) => (
                <div key={i} style={{ padding: '0.75rem', borderRadius: '0.5rem', backgroundColor: '#0f172a', marginBottom: '0.5rem', borderLeft: `4px solid ${alert.status === 'blocked' ? '#ef4444' : '#f59e0b'}` }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <p style={{ fontSize: '0.875rem', fontWeight: 'bold', margin: 0 }}>{alert.merchant}</p>
                    <span style={{ fontSize: '0.75rem', color: '#64748b' }}>{alert.time}</span>
                  </div>
                  <p style={{ fontSize: '0.8rem', color: '#ef4444', margin: '0.25rem 0' }}>{alert.status.toUpperCase()}: {alert.amount}</p>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      <style>
        {`
          @keyframes pulse {
            0% { transform: scale(1); }
            50% { transform: scale(1.05); border-color: #ef4444; }
            100% { transform: scale(1); }
          }
        `}
      </style>
    </header>
  );
};

export default Header;
